  "code": "@startuml\nclass User {\n  ID: String\n  name: String\n  email: String\n  dateOfBirth: Date\n}\n\nclass Account {\n  accountNumber: Integer\n  type: String\n}\n\nclass BusinessAccount {\n  companyName: String\n  monthlyFee: Decimal\n}\n\nclass PersonalAccount {\n}\n\nclass Page {\n  pageName: String\n  visits: Integer\n}\n\nclass AdvertisementPage {\n  bounceRate: Decimal\n  clickThroughRate: Decimal\n  conversionRate: Decimal\n}\n\nUser ||--o{ Account : creates\nAccount ||--o{ Page : administrates\nAccount ||--|| BusinessAccount : extends\nAccount ||--|| PersonalAccount : extends\nPage ||--|| AdvertisementPage : extends\nPersonalAccount ||--o{ Page : can access\n@enduml"
}"
